import './App.css';
import React, { useEffect, useState } from 'react';
import axios from 'axios';
import io from 'socket.io-client';

const socket = io('http://localhost:5001');

const App = () => {
  const [questions, setQuestions] = useState([]);
  const [category, setCategory] = useState('Mixed');  // Default to 'Mixed' category
  const [solvedQuestions, setSolvedQuestions] = useState([]);
  const [selectedAnswers, setSelectedAnswers] = useState({});

  useEffect(() => {
    const fetchQuestions = async () => {
      try {
        const res = await axios.get('/api/questions', { params: { category } });
        setQuestions(res.data);
      } catch (error) {
        console.error('Error fetching questions:', error);
      }
    };

    const fetchSolvedState = async () => {
      try {
        const res = await axios.get('/api/solved', {
          params: { userId: 'USER_ID' } // Adjust how you derive userId
        });
        setSolvedQuestions(res.data.solvedQuestions || []);
      } catch (error) {
        console.error('Error fetching solved state:', error);
      }
    };

    fetchQuestions();
    fetchSolvedState();

    socket.on('updateSolved', (data) => {
      setSolvedQuestions((prevState) => {
        if (!prevState.includes(data.questionId)) {
          return [...prevState, data.questionId];
        }
        return prevState;
      });
    });

    return () => {
      socket.off('updateSolved');
    };

  }, [category]);

  // const socket = io('http://localhost:5001');

  socket.on('connect', () => {
    console.log('Connected to server');
  });

  // useEffect(() => {
  //   socket.on('updateSolved', (data) => {
  //     console.log('Real-time update received:', data);
  //   });

  //   return () => {
  //     socket.off('updateSolved');
  //   };
  // }, []);

  // useEffect(() => {
  //   // const socket = io('http://localhost:5001');

  //   socket.on('updateSolved', (data) => {
  //     if (!solvedQuestions.includes(data.questionId)) {
  //       setSolvedQuestions((prev) => [...prev, data.questionId]);
  //       // setSolvedQuestions([...solvedQuestions, data.questionId]);
  //     }
  //   });

  //   return () => {
  //     socket.off('updateSolved');
  //     // socket.disconnect();
  //   };
  // }, [solvedQuestions]);

  // useEffect(() => {
  //   socket.on('updateSolved', (data) => {
  //     setSolvedQuestions((prevState) => {
  //       if (!prevState.includes(data.questionId)) {
  //         return [...prevState, data.questionId];
  //       }
  //       return prevState;
  //     });
  //   });

  //   return () => {
  //     socket.off('updateSolved');
  //   };
  // }, []);

  const handleAnswerChange = (questionId, optionIndex) => {
    setSelectedAnswers({
      ...selectedAnswers,
      [questionId]: optionIndex,
    });

    const question = questions.find(q => q._id === questionId);
    // if (optionIndex === question.correct) 
    if (optionIndex === question.correct && !solvedQuestions.includes(questionId)) {
      const socket = io('http://localhost:5001');
      socket.emit('solveQuestion', { questionId }); // Adjust userId
    }

  };



  return (
    <div>
      <select className='category-dropdown' onChange={(e) => setCategory(e.target.value)} value={category}>
        <div>
          <option value="Mixed">Mixed</option>
          <option value="Political">Political</option>
          <option value="Literature">Literature</option>
          {/*  more categories as needed */}
        </div>

      </select>



      {/* <h2>{`${solvedQuestions.length}/${questions.length} Questions Solved`}</h2> */}
      <div className='grid-container'>
        {questions.map((q) => (
          <div
            key={q._id}
            className={`grid-item ${solvedQuestions.includes(q._id) ? 'correct' : ''}`}
          >
            <p>{q.question}</p>
            {q.options.map((option, index) => (
              <label key={index}>
                <input
                  type="radio"
                  name={`question-${q._id}`}
                  checked={selectedAnswers[q._id] === index}
                  onChange={() => handleAnswerChange(q._id, index)}
                />
                {option}
              </label>
            ))}
          </div>
        ))}
      </div>
    </div>

  );

};

export default App;
